def has_duplicate(nums):
    seen = set()
    for n in nums:
        if n in seen:
            return True
        seen.add(n)
    return False

def flatten(nested_list):
    # Handle None input
    if nested_list is None:
        return []
    # Handle empty list
    if nested_list == []:
        return []
    result = []
    for item in nested_list:
        # Handle None items
        if item is None:
            continue
        # Recursively flatten if item is a list or tuple
        if isinstance(item, (list, tuple)):
            result.extend(flatten(item))
        # Only include integers (skip strings, dicts, etc.)
        elif isinstance(item, int):
            result.append(item)
    return result

import time
from collections import deque

class RateLimiter:
    """
    Simple sliding-window rate limiter allowing at most N calls per window_seconds.
    Uses timestamps, not sleep. Thread-safe only if external locking is used.
    """

    def __init__(self, n, window_seconds):
        if n is None or window_seconds is None:
            raise ValueError("n and window_seconds must not be None")
        if not isinstance(n, int) or isinstance(n, bool):
            raise TypeError("n must be an integer")
        if not isinstance(window_seconds, (int, float)) or isinstance(window_seconds, bool):
            raise TypeError("window_seconds must be a number")
        if n < 0:
            raise ValueError("n must be non-negative")
        if window_seconds <= 0:
            raise ValueError("window_seconds must be positive")
        self.n = n
        self.window_seconds = float(window_seconds)
        self._timestamps = deque()

    def allow(self, now=None):
        """
        Return True if the call is allowed under the rate limit, False otherwise.
        Optional `now` parameter for deterministic testing; defaults to time.time().
        """
        if now is None:
            now = time.time()
        elif not isinstance(now, (int, float)) or isinstance(now, bool):
            raise TypeError("now must be a number or None")

        # Remove timestamps that fell outside the current window
        cutoff = now - self.window_seconds
        while self._timestamps and self._timestamps[0] <= cutoff:
            self._timestamps.popleft()

        if len(self._timestamps) < self.n:
            self._timestamps.append(now)
            return True
        return False

    def reset(self):
        """Clear all recorded timestamps."""
        self._timestamps.clear()

    def remaining(self, now=None):
        """Return the number of additional calls allowed in the current window."""
        if now is None:
            now = time.time()
        elif not isinstance(now, (int, float)) or isinstance(now, bool):
            raise TypeError("now must be a number or None")

        cutoff = now - self.window_seconds
        while self._timestamps and self._timestamps[0] <= cutoff:
            self._timestamps.popleft()

        return max(0, self.n - len(self._timestamps))

def fibonacci(n):
    if n <= 0:
        return 0
    a, b = 0, 1
    for _ in range(2, n + 1):
        a, b = b, a + b
    return b
